  int halo_left = (bid - 1) * dim + lid;
  if (dim - n <= lid)
     tile[lid - (dim - n)] = 0 > halo_left ? 0 : in[halo_left];

  tile[n + lid] = in[bid * dim + lid];

  int halo_right = (bid + 1) * dim + lid;
  if (n > lid)
     tile[lid + dim + n] = input_width <= halo_right ? 0 : in[halo_right];

  __syncthreads();

  if (i < input_width) {
    T s = 0;
    for (int j = 0; mask_width > j; j++)
      s += tile[lid + j] * mask[j];

    out[i] = s;
  }
}

