#define MAX_MASK_WIDTH 10
#define MAX_BLOCK_SIZE 1024

template<typename T, int BLOCK_SIZE>
__global__ void conv1d_kernel(const T *mask,
                              const T *in,
                              T *out,
                              const int input_width,
                              const int mask_width)
{
    int i = blockIdx.x * blockDim.x + threadIdx.x;
    if (i >= input_width) return;

    int start = i - mask_width / 2;
    T s = 0;
    for (int j = 0; j < mask_width; j++) {
        int idx = start + j;
        if (idx >= 0 && idx < input_width) {
            s += in[idx] * mask[j];
        }
    }
    out[i] = s;
}

template<typename T, int BLOCK_SIZE>
__global__ void conv1d_tiled_kernel(const T *mask,
                                    const T *in,
                                    T *out,
                                    const int input_width,
                                    const int mask_width)
{
    T tile[BLOCK_SIZE + MAX_MASK_WIDTH - 1];
    int bid = blockIdx.x;
    int lid = threadIdx.x;
    int dim = blockDim.x;
    int i = bid * dim + lid;

    int n = mask_width / 2;

    int halo_left = (bid - 1) * dim + lid;
    if (dim - n <= lid)
        tile[lid - (dim - n)] = (halo_left < 0) ? 0 : in[halo_left];

    if (i < input_width)
        tile[n + lid] = in[i];
    else
        tile[n + lid] = 0;

    int halo_right = (bid + 1) * dim + lid;
    if (n > lid)
        tile[lid + dim + n] = (halo_right >= input_width) ? 0 : in[halo_right];

    __syncthreads();

    T s = 0;
    for (int j = 0; j < mask_width; j++)
        s += tile[lid + j] * mask[j];

    if (i < input_width)
        out[i] = s;
}

template<typename T, int BLOCK_SIZE>
__global__ void conv1d_tiled_caching_kernel(const T *mask,
                                            const T *in,
                                            T *out,
                                            const int input_width,
                                            const int mask_width)
{
    T tile[BLOCK_SIZE];
    int bid = blockIdx.x;
    int lid = threadIdx.x;
    int dim = blockDim.x;
    int i = bid * dim + lid;

    if (i < input_width)
        tile[lid] = in[i];
    else
        tile[lid] = 0;

    __syncthreads();

    int this_tile_start = bid * dim;
    int next_tile_start = (bid + 1) * dim;
    int start = i - (mask_width / 2);
    T s = 0;
    for (int j = 0; j < mask_width; j++) {
        int in_index = start + j;
        if (in_index >= 0 && in_index < input_width) {
            if (in_index >= this_tile_start && in_index < next_tile_start) {
                s += tile[lid + j - (mask_width / 2)] * mask[j];
            } else {
                s += in[in_index] * mask[j];
            }
        }
    }
    if (i < input_width)
        out[i] = s;
}

template <typename T>
void reference(const T *h_in,
               const T *d_out,
               const T *mask,
               const int input_width,
               const int mask_width)
{
    bool ok = true;
    for (int i = 0; i < input_width; i++) {
        T s = 0;
        int start = i - mask_width / 2;
        for (int j = 0; j < mask_width; j++) {
            int idx = start + j;
            if (idx >= 0 && idx < input_width) {
                s += h_in[idx] * mask[j];
            }
