#include <stdlib.h>
#include <stdio.h>
#include <string.h>
#include <assert.h>
#include <sys/time.h>
#include <math.h>
#include <utility>
#include <cuda_runtime.h>

#define NTX 16
#define NTY 16

double stop_watch(double t0)
{
  double time;
  struct timeval t;
  gettimeofday(&t, NULL);
  time = t.tv_sec * 1e6 + t.tv_usec;
  return time-t0;
}

void usage(char *argv[]) {
  fprintf(stderr, " Usage: %s LX LY NITER\n", argv[0]);
  return;
}

void reference(float *out, const float *in, const float delta, const float norm, const int Lx, const int Ly)
{
  for (int y = 0; y < Ly; y++) {
    for (int x = 0; x < Lx; x++) {
      int v00 = y*Lx + x;
      int v0p = y*Lx + (x + 1)%Lx;
      int v0m = y*Lx + (Lx + x - 1)%Lx;
      int vp0 = ((y+1)%Ly)*Lx + x;
      int vm0 = ((Ly+y-1)%Ly)*Lx + x;
      out[v00] = norm*in[v00] + delta*(in[v0p] + in[v0m] + in[vp0] + in[vm0]);
    }
  }
}

__global__ void dev_lapl_iter_kernel(float *out, const float *in, const float delta, const float norm, const int Lx, const int Ly)
{
  int x = blockIdx.x * blockDim.x + threadIdx.x;
  int y = blockIdx.y * blockDim.y + threadIdx.y;

  if (x < Lx && y < Ly) {
    int v00 = y*Lx + x;
    int v0p = y*Lx + (x + 1)%Lx;
    int v0m = y*Lx + (Lx + x - 1)%Lx;
    int vp0 = ((y+1)%Ly)*Lx + x;
    int vm0 = ((Ly+y-1)%Ly)*Lx + x;
    out[v00] = norm*in[v00] + delta*(in[v0p] + in[v0m] + in[vp0] + in[vm0]);
  }
}

void dev_lapl_iter(float *out, const float *in, const float delta, const float norm, const int Lx, const int Ly)
{
  dim3 blockDim(NTX, NTY);
  dim3 gridDim(Lx/NTX, Ly/NTY);

  dev_lapl_iter_kernel<<<gridDim, blockDim>>>(out, in, delta, norm, Lx, Ly);
  cudaDeviceSynchronize();
}

int main(int argc, char *argv[]) {

  if(argc != 4) {
    usage(argv);
    exit(1);
  }

  int Lx = atoi(argv[1]);
  int Ly = atoi(argv[2]);
  if (Lx % NTX != 0 ||  Ly % NTY != 0) {
    printf("Array length LX and LY must be a multiple of block size %d and %d, respectively\n",
          NTX, NTY);
    exit(1);
  }

  int niter = atoi(argv[3]);
  assert(niter >= 1);


  const float sigma = 0.01;
  const float xdelta = sigma / (1.0+4.0*sigma);
  const float xnorm = 1.0/(1.0+4.0*sigma);

  printf(" Ly,Lx = %d,%d\n", Ly, Lx);
  printf(" niter = %d\n", niter);


  srand(123);
  float *buffer = (float*) malloc(sizeof(float)*Lx*Ly);
  float *h_out = (float*) malloc(sizeof(float)*Lx*Ly);
  float *h_in  = (float*) malloc(sizeof(float)*Lx*Ly);

  int i, j, ii, jj;
  for (i = 0; i < Lx; i += 16) {
    ii = rand() % Lx;
    for (j = 0; j < Ly; j++)
       buffer[ii + j*Lx] = 1.f;
  }
  for (i = 0; i < Ly; i += 16) {
    jj = rand() % Ly;
    for (j = 0; j < Lx; j++)
       buffer[j + jj*Lx] = 1.f;
  }
  memcpy(h_in, buffer, sizeof(float)*Lx*Ly);

  for(i=0; i<niter; i++) {
    reference (h_out, h_in, xdelta, xnorm, Lx, Ly);
    std::swap(h_out, h_in);
  }

  float *d_out = NULL;
  float *d_in  = NULL;
  cudaMalloc(&d_out, sizeof(float)*Lx*Ly);
  cudaMalloc(&d_in, sizeof(float)*Lx*Ly);
  cudaMemcpy(d_in, buffer, sizeof(float)*Lx*Ly, cudaMemcpyHostToDevice);

  double t0;

  t0 = stop_watch(0);
  for(i=0; i<niter; i++) {
    dev_lapl_iter(d_out, d_in, xdelta, xnorm, Lx, Ly);
    std::swap(d_out, d_in);
  }
  t0 = stop_watch(t0)/(double)niter;

  printf("Device: iters = %8d, (Lx,Ly) = %6d, %6d, t = %8.1f usec/iter, BW = %6.3f GB/s, P = %6.3f Gflop/s\n",
  	 niter, Lx, Ly, t0,
  	 Lx*Ly*sizeof(float)*2.0/(t0*1.0e3),
  	 (Lx*Ly*6.0)/(t0*1.0e3));


  float *h_d_in = (float*) malloc(sizeof(float)*Lx*Ly);
  cudaMemcpy(h_d_in, d_in, sizeof(float)*Lx*Ly, cudaMemcpyDeviceToHost);

  bool ok = true;
  for (i = 0; i < Lx*Ly; i++) {

    if ( fabs(h_in[i] - h_d_in[i]) > 1e-2 ) {
      printf("Mismatch at %d cpu=%f gpu=%f\n", i, h_in[i], h_d_in[i]);
      ok = false;
      break;
    }
  }
  printf("%s\n", ok ? "PASS" : "FAIL");

  free(buffer);
  free(h_out);
  free(h_in);
  free(h_d_in);
  cudaFree(d_in);
  cudaFree(d_out);
  return 0;
}

